// Detect Chrome path - try macOS first, then Linux
const getChromePath = () => {
	try {
		execSync("test -f '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome'", { stdio: "ignore" });
		return "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
	} catch {}
	try {
		execSync("which google-chrome", { stdio: "pipe" });
		return "google-chrome";
	} catch {}
	try {
		execSync("which chromium", { stdio: "pipe" });
		return "chromium";
	} catch {}
	try {
		execSync("which chromium-browser", { stdio: "pipe" });
		return "chromium-browser";
	} catch {}
	throw new Error("Chrome not found. Install Google Chrome or Chromium.");
};

const chromePath = getChromePath();

// Start Chrome with flags to force new instance
spawn(
	chromePath,
	[
		"--remote-debugging-port=9222",
		`--user-data-dir=${SCRAPING_DIR}`,
		"--no-first-run",
		"--no-default-browser-check",
		"--no-sandbox", // Required for running as root/some Linux setups
		"--disable-setuid-sandbox",
	],
	{ detached: true, stdio: "ignore" },
).unref();

